"use client";
import { useState, useEffect } from 'react';
import axios from 'axios';
import PostCard from '@/components/PostCard';
import { Loader2 } from 'lucide-react';

export default function Home() {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const res = await axios.get(`${process.env.NEXT_PUBLIC_API_URL}/posts/published`);
        setPosts(res.data);
      } catch (error) {
        console.error("שגיאה במשיכת הפוסטים:", error);
      } finally {
        setLoading(false);
      }
    };
    fetchPosts();
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen bg-zinc-950 flex justify-center items-center">
        <Loader2 className="w-12 h-12 animate-spin text-purple-500" />
      </div>
    );
  }

  return (
    // שינינו פה את הרקע ל-zinc-950
    <main className="flex-grow py-12 px-4 md:px-8">
      <div className="max-w-7xl mx-auto">
        <div className="text-center mb-16">
          <h1 className="text-4xl md:text-6xl font-black text-white mb-4 tracking-tight">
            החדשות החמות בעולם <span className="text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-purple-600">האנימה</span>
          </h1>
          <p className="text-zinc-400 text-lg md:text-xl max-w-2xl mx-auto">
            עדכונים שוטפים, כותרות וידיעות שנאספו ונכתבו על ידי סוכני הבינה המלאכותית שלנו.
          </p>
        </div>

        {posts.length === 0 ? (
          <div className="text-center text-zinc-500 py-12 bg-zinc-900 rounded-2xl border border-zinc-800">
            אין כרגע פוסטים מפורסמים.
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {posts.map(post => (
              <PostCard key={post._id} post={post} />
            ))}
          </div>
        )}
      </div>
    </main>
  );
}